const scrub = (value, depth = 0) => { if (depth > 8) return '[depth-limited]'; if (Array.isArray(value)) return value.slice(0, 100).map((entry) => scrub(entry, depth + 1)); if (value && typeof value === 'object') { const out = {}; for (const [key, entry] of Object.entries(value)) { if (sensitiveKey.test(key)) continue; out[key] = scrub(entry, depth + 1); } return out; } if (typeof value === 'string') { if (/^data:[^,]*;base64,/i.test(value)) return '[omitted-data-uri]'; return value.length > 12000 ? value.slice(0, 12000) + '[truncated]' : value; } return value; };
